import{_ as t,o as s,c as e,ai as n}from"./chunks/framework.C4ntERNc.js";const g=JSON.parse('{"title":"--tristate-default Compiler Flag","description":"","frontmatter":{"title":"--tristate-default Compiler Flag","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/tristate-default.md","filePath":"reference-manual/tristate-default.md"}'),i={name:"reference-manual/tristate-default.md"};function l(r,a,o,p,d,c){return s(),e("div",null,[...a[0]||(a[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/tristate-default.md for this page in Markdown format</div><h1 id="tristate-default-compiler-flag" tabindex="-1"><code>--tristate-default</code> Compiler Flag <a class="header-anchor" href="#tristate-default-compiler-flag" aria-label="Permalink to “--tristate-default Compiler Flag”">​</a></h1><h2 id="purpose-and-overview" tabindex="-1">Purpose and Overview <a class="header-anchor" href="#purpose-and-overview" aria-label="Permalink to “Purpose and Overview”">​</a></h2><p>The <code>--tristate-default</code> flag converts <strong>internal tri-state nets</strong> into explicit priority-chained conditional logic, eliminating high-impedance (<code>z</code>) states for synthesis targets that do not support internal tri-state (such as most FPGA implementations).</p><p>This flag enables a single JZ-HDL design to function on both ASIC platforms (which support tri-state) and FPGA platforms (which do not), without requiring design changes.</p><p><strong>Syntax:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jz-hdl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tristate-default=GND</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   design.jz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Replace z with 0 (GND)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jz-hdl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tristate-default=VCC</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   design.jz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Replace z with 1 (VCC)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jz-hdl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">                          design.jz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # Default: allow z (ASIC/Sim mode)</span></span></code></pre></div><p><strong>Effect:</strong></p><ul><li>When <code>--tristate-default=GND</code> or <code>--tristate-default=VCC</code> is specified: <ul><li>All tri-state nets (nets with multiple drivers, at least one assigning <code>z</code>) are identified.</li><li>Each tri-state net is transformed into a priority-chained mux with a default value (<code>0</code> or <code>1</code>).</li><li>External INOUT_PINS remain unchanged (their tri-state behavior is preserved for I/O pads).</li></ul></li><li>When the flag is omitted (default): <ul><li>Tri-state nets are permitted; no transformation occurs.</li><li>Behavior is consistent with ASIC or simulation semantics.</li></ul></li></ul><h2 id="applicability-and-scope" tabindex="-1">Applicability and Scope <a class="header-anchor" href="#applicability-and-scope" aria-label="Permalink to “Applicability and Scope”">​</a></h2><h3 id="applicable-contexts" tabindex="-1">Applicable Contexts <a class="header-anchor" href="#applicable-contexts" aria-label="Permalink to “Applicable Contexts”">​</a></h3><p>The <code>--tristate-default</code> flag transformation applies to:</p><ul><li><strong>ASYNCHRONOUS blocks only</strong> (combinational tri-state nets).</li><li>Tri-state nets driven by multiple drivers, where at least one driver assigns <code>z</code> and the others assign <code>0</code>, <code>1</code>, or expressions.</li><li>Internal nets: <code>WIRE</code>, <code>PORT</code>, and implicit nets created by aliasing.</li></ul><h3 id="non-applicable-contexts" tabindex="-1">Non-Applicable Contexts <a class="header-anchor" href="#non-applicable-contexts" aria-label="Permalink to “Non-Applicable Contexts”">​</a></h3><p>The transformation does <strong>not</strong> apply to:</p><ul><li><strong>SYNCHRONOUS blocks</strong> (registers and latches cannot hold or produce <code>z</code>; tri-state in synchronous context is invalid per the core concepts specification).</li><li><strong>INOUT ports on the top-level module</strong> when mapped to INOUT_PINS (tri-state is preserved as an I/O pad property).</li><li><strong>External blackbox ports</strong> (transformation is not applied to opaque module interfaces).</li><li><strong>Single-driver nets</strong> (nets with only one driver are not tri-state, regardless of whether that driver assigns <code>z</code>).</li></ul><h2 id="tri-state-net-identification" tabindex="-1">Tri-State Net Identification <a class="header-anchor" href="#tri-state-net-identification" aria-label="Permalink to “Tri-State Net Identification”">​</a></h2><p>A net is classified as tri-state when all three criteria are met:</p><ol><li>The net has <strong>two or more drivers</strong> in the same ASYNCHRONOUS block.</li><li><strong>At least one driver</strong> assigns <code>z</code> (high-impedance) in some execution path.</li><li>The net is <strong>not excluded</strong> from transformation (i.e., it is not a top-level INOUT pin or blackbox port).</li></ol><h2 id="transformation-algorithm" tabindex="-1">Transformation Algorithm <a class="header-anchor" href="#transformation-algorithm" aria-label="Permalink to “Transformation Algorithm”">​</a></h2><h3 id="priority-chain-conversion" tabindex="-1">Priority-Chain Conversion <a class="header-anchor" href="#priority-chain-conversion" aria-label="Permalink to “Priority-Chain Conversion”">​</a></h3><p>Once a tri-state net is identified, it is converted to a <strong>priority-chained ternary cascade</strong> using the following transformation:</p><p><strong>Original (tri-state):</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>signal &lt;=  cond₀ ? data₀ : N&#39;bz;</span></span>
<span class="line"><span>signal &lt;=  cond₁ ? data₁ : N&#39;bz;</span></span>
<span class="line"><span>signal &lt;=  cond₂ ? data₂ : N&#39;bz;</span></span></code></pre></div><p><strong>Transformed (with --tristate-default=GND):</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>signal &lt;=  cond₀ ? data₀ :</span></span>
<span class="line"><span>           cond₁ ? data₁ :</span></span>
<span class="line"><span>           cond₂ ? data₂ :</span></span>
<span class="line"><span>           N&#39;h00;</span></span></code></pre></div><p><strong>Transformed (with --tristate-default=VCC):</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>signal &lt;=  cond₀ ? data₀ :</span></span>
<span class="line"><span>           cond₁ ? data₁ :</span></span>
<span class="line"><span>           cond₂ ? data₂ :</span></span>
<span class="line"><span>           N&#39;hFF;</span></span></code></pre></div><p><strong>Semantics:</strong></p><ul><li><strong>Source order determines priority:</strong> Drivers are chained in the order they appear in the source code; the first driver to assert its condition wins.</li><li><strong>Default on all <code>z</code>:</strong> If no condition is true, the net assumes the default value (<code>N&#39;h00</code> for GND, <code>N&#39;hFF</code> for VCC).</li><li><strong>Behavioral equivalence:</strong> If conditions are mutually exclusive and exactly one is true in every cycle, the transformed logic produces the same result as the original tri-state.</li></ul><h3 id="whole-signal-transformation-policy" tabindex="-1">Whole-Signal Transformation Policy <a class="header-anchor" href="#whole-signal-transformation-policy" aria-label="Permalink to “Whole-Signal Transformation Policy”">​</a></h3><p>The transformation is applied <strong>whole-signal</strong>, not per-bit.</p><p><strong>Rationale:</strong></p><ul><li>Simpler to reason about and implement.</li><li>Cleaner generated logic (single mux chain vs. per-bit decomposition).</li><li>Reduces edge cases and compiler complexity.</li></ul><p><strong>Constraint:</strong> If individual bits of the same signal have <strong>different sets of drivers</strong>, a compile-time error is issued:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ERROR: TRISTATE_TRANSFORM_PER_BIT_FAIL</span></span>
<span class="line"><span>Cannot transform tri-state net &#39;signal&#39;: drivers are not uniform across all bits.</span></span>
<span class="line"><span>Bits [7:4] driven by {driver_a, driver_b}; bits [3:0] driven by {driver_c}.</span></span>
<span class="line"><span>Per-bit tri-state transformation is not supported.</span></span></code></pre></div><p>If such a situation is encountered, the user must manually refactor to ensure all bits of the signal have the same driver set.</p><h2 id="validation-rules" tabindex="-1">Validation Rules <a class="header-anchor" href="#validation-rules" aria-label="Permalink to “Validation Rules”">​</a></h2><p>After transformation, the generated priority-chain mux is verified to:</p><ol><li><strong>Maintain Width:</strong> Result width matches original signal width.</li><li><strong>Valid Ternary Nesting:</strong> All operands and branch widths are compatible.</li><li><strong>No Side Effects:</strong> Conditions are pure (no assignment side effects).</li><li><strong>No New Loops:</strong> The priority chain does not introduce new combinational loops.</li></ol><p>If any post-transformation check fails, the transformation is <strong>rolled back</strong>, and a compile error is issued.</p><h2 id="handling-of-inout-ports-and-external-pins" tabindex="-1">Handling of INOUT Ports and External Pins <a class="header-anchor" href="#handling-of-inout-ports-and-external-pins" aria-label="Permalink to “Handling of INOUT Ports and External Pins”">​</a></h2><p><strong>INOUT ports on the top-level module</strong> that are mapped to <code>INOUT_PINS</code> in the project retain their full tri-state semantics, <strong>regardless of the <code>--tristate-default</code> flag</strong>.</p><p><strong>Rationale:</strong> INOUT_PINS represent physical I/O pads, which are inherently tri-state hardware. The flag only affects internal tri-state nets.</p><p><strong>Example:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// INOUT port on top module</span></span>
<span class="line"><span>PORT {</span></span>
<span class="line"><span>  INOUT [8] data_bus;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Mapped to INOUT_PIN in project</span></span>
<span class="line"><span>INOUT_PINS {</span></span>
<span class="line"><span>  data_bus [8] = { standard=LVCMOS33, drive=8 };</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// In ASYNCHRONOUS block: tri-state is NOT transformed</span></span>
<span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  data_bus &lt;= enable ? output_data : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>  // Remains tri-state; flag does not apply</span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="driving-inout-with-internal-tri-state" tabindex="-1">Driving INOUT with Internal Tri-State <a class="header-anchor" href="#driving-inout-with-internal-tri-state" aria-label="Permalink to “Driving INOUT with Internal Tri-State”">​</a></h3><p>If an internal tri-state net is <strong>connected to</strong> an INOUT port, the transformation applies to the internal net, but the connection to the INOUT port remains valid.</p><p><strong>Example:</strong></p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>WIRE {</span></span>
<span class="line"><span>  internal_mux [8];</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT {</span></span>
<span class="line"><span>  INOUT [8] bus;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  // internal_mux is tri-state; will be transformed</span></span>
<span class="line"><span>  internal_mux &lt;= cond_a ? data_a : 8&#39;bz;</span></span>
<span class="line"><span>  internal_mux &lt;= cond_b ? data_b : 8&#39;bz;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  // Connect to INOUT (tri-state preserved for I/O pad)</span></span>
<span class="line"><span>  bus &lt;= enable ? internal_mux : 8&#39;bzzzz_zzzz;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>With <code>--tristate-default=GND</code>:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  internal_mux &lt;= cond_a ? data_a :</span></span>
<span class="line"><span>                  cond_b ? data_b :</span></span>
<span class="line"><span>                  GND;  // Transformed</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  bus &lt;= enable ? internal_mux : 8&#39;bzzzz_zzzz;  // Unchanged</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="error-conditions-and-warnings" tabindex="-1">Error Conditions and Warnings <a class="header-anchor" href="#error-conditions-and-warnings" aria-label="Permalink to “Error Conditions and Warnings”">​</a></h2><h3 id="transformation-errors" tabindex="-1">Transformation Errors <a class="header-anchor" href="#transformation-errors" aria-label="Permalink to “Transformation Errors”">​</a></h3><p>A compile error is issued if:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Error</th><th style="text-align:left;">Cause</th><th style="text-align:left;">Mitigation</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_MUTUAL_EXCLUSION_FAIL</strong></td><td style="text-align:left;">Conditions are not provably mutually exclusive</td><td style="text-align:left;">Refactor to use explicit <code>IF</code>/<code>ELIF</code>/<code>ELSE</code> or add explicit guards to ensure exclusion</td></tr><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_PER_BIT_FAIL</strong></td><td style="text-align:left;">Different bits have different driver sets</td><td style="text-align:left;">Restructure so all bits share the same drivers</td></tr><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_BLACKBOX_PORT</strong></td><td style="text-align:left;">Attempting to transform external blackbox port</td><td style="text-align:left;">Tri-state in opaque modules is preserved as-is</td></tr><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_OE_EXTRACT_FAIL</strong></td><td style="text-align:left;">Cannot extract output-enable condition from a driver</td><td style="text-align:left;">Refactor driver to use a clear <code>condition ? data : z</code> pattern</td></tr></tbody></table><h3 id="warnings" tabindex="-1">Warnings <a class="header-anchor" href="#warnings" aria-label="Permalink to “Warnings”">​</a></h3><p>A warning is issued in these cases (transformation proceeds unless conversion is explicitly forbidden):</p><table tabindex="0"><thead><tr><th style="text-align:left;">Warning</th><th style="text-align:left;">Cause</th><th style="text-align:left;">Recommendation</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_SINGLE_DRIVER</strong></td><td style="text-align:left;">Net marked as tri-state but only one driver present in execution</td><td style="text-align:left;">Remove unnecessary <code>z</code> assignment; net is not actually tri-state</td></tr><tr><td style="text-align:left;"><strong>TRISTATE_TRANSFORM_UNUSED_DEFAULT</strong></td><td style="text-align:left;">All execution paths covered; default value never used</td><td style="text-align:left;">Consider the transformation unnecessary; default is unreachable</td></tr></tbody></table><h2 id="portability-guidelines" tabindex="-1">Portability Guidelines <a class="header-anchor" href="#portability-guidelines" aria-label="Permalink to “Portability Guidelines”">​</a></h2><h3 id="best-practices-for-portable-designs" tabindex="-1">Best Practices for Portable Designs <a class="header-anchor" href="#best-practices-for-portable-designs" aria-label="Permalink to “Best Practices for Portable Designs”">​</a></h3><p>To write JZ-HDL designs that work with and without <code>--tristate-default</code>:</p><ol><li><p><strong>Use explicit guards:</strong> Prefer <code>IF</code>/<code>ELIF</code>/<code>ELSE</code> over independent conditional assignments.</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// Good: explicit structure</span></span>
<span class="line"><span>IF (sel == 2&#39;b00) {</span></span>
<span class="line"><span>  data &lt;= rom_data;</span></span>
<span class="line"><span>} ELIF (sel == 2&#39;b01) {</span></span>
<span class="line"><span>  data &lt;= ram_data;</span></span>
<span class="line"><span>} ELSE {</span></span>
<span class="line"><span>  data &lt;= 8&#39;h00;  // Explicit default</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Less ideal: separate assignments (harder to transform)</span></span>
<span class="line"><span>data &lt;= (sel == 2&#39;b00) ? rom_data : 8&#39;bz;</span></span>
<span class="line"><span>data &lt;= (sel == 2&#39;b01) ? ram_data : 8&#39;bz;</span></span></code></pre></div></li><li><p><strong>Limit tri-state to I/O boundaries:</strong> Keep tri-state logic at top-level INOUT ports; use internal muxes elsewhere.</p></li><li><p><strong>Test both modes:</strong> Verify design behavior with and without the flag.</p></li></ol>`,63)])])}const u=t(i,[["render",l]]);export{g as __pageData,u as default};
